import{_ as r,o as t,c as a,ag as s}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Enregistrement du temps","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/time-registration.md","filePath":"fr/features/time-registration.md"}'),i={name:"fr/features/time-registration.md"};function l(n,e,o,u,d,m){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="enregistrement-du-temps" tabindex="-1">Enregistrement du temps <a class="header-anchor" href="#enregistrement-du-temps" aria-label="Permalink to &quot;Enregistrement du temps&quot;">​</a></h1><p>Enregistrez vos heures de travail par projet et par client pour suivre le temps facturable et generer des factures a partir des entrees de temps.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>L&#39;enregistrement du temps vous aide a :</p><ul><li>Suivre combien d&#39;heures vous consacrez a chaque projet</li><li>Calculer le temps facturable vs. non facturable</li><li>Generer des factures directement a partir des heures enregistrees</li><li>Comprendre votre taux horaire effectif</li></ul><h2 id="enregistrer-du-temps" tabindex="-1">Enregistrer du temps <a class="header-anchor" href="#enregistrer-du-temps" aria-label="Permalink to &quot;Enregistrer du temps&quot;">​</a></h2><h3 id="creer-une-entree-de-temps" tabindex="-1">Creer une entree de temps <a class="header-anchor" href="#creer-une-entree-de-temps" aria-label="Permalink to &quot;Creer une entree de temps&quot;">​</a></h3><ol><li>Allez dans <strong>Enregistrement du temps</strong></li><li>Cliquez sur <strong>Ajouter une entree</strong> (ou le bouton + sur mobile)</li><li>Remplissez : <ul><li><strong>Date</strong> -- Quand le travail a ete effectue</li><li><strong>Heures</strong> -- Duree du travail</li><li><strong>Projet</strong> -- A quel projet le temps est destine</li><li><strong>Client</strong> -- Le client (rempli automatiquement a partir du projet)</li><li><strong>Description</strong> -- Ce sur quoi vous avez travaille</li><li><strong>Facturable</strong> -- Si ce temps doit etre facture</li><li><strong>Taux horaire</strong> -- Votre tarif pour ce travail</li></ul></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><h3 id="mode-heures-uniquement" tabindex="-1">Mode heures uniquement <a class="header-anchor" href="#mode-heures-uniquement" aria-label="Permalink to &quot;Mode heures uniquement&quot;">​</a></h3><p>Pour un suivi du temps simplifie, activez le mode heures uniquement dans les parametres. Cela masque le taux horaire et les champs de facturation, n&#39;affichant que les heures et la description.</p><h2 id="facturer-les-entrees-de-temps" tabindex="-1">Facturer les entrees de temps <a class="header-anchor" href="#facturer-les-entrees-de-temps" aria-label="Permalink to &quot;Facturer les entrees de temps&quot;">​</a></h2><p>Convertissez les heures enregistrees en factures :</p><ol><li>Filtrez les entrees de temps par client ou projet</li><li>Selectionnez les entrees que vous souhaitez facturer</li><li>Cliquez sur <strong>Creer une facture</strong></li><li>Une nouvelle facture est pre-remplie avec les lignes correspondant aux entrees de temps selectionnees</li><li>Verifiez et envoyez</li></ol><h3 id="parametres-de-facturation-automatique" tabindex="-1">Parametres de facturation automatique <a class="header-anchor" href="#parametres-de-facturation-automatique" aria-label="Permalink to &quot;Parametres de facturation automatique&quot;">​</a></h3><p>Configurez la facturation automatique pour les entrees de temps :</p><ol><li>Allez dans les parametres d&#39;enregistrement du temps</li><li>Configurez les regles de facturation automatique</li><li>Les entrees de temps correspondant aux regles sont automatiquement ajoutees aux factures</li></ol><h2 id="filtrage" tabindex="-1">Filtrage <a class="header-anchor" href="#filtrage" aria-label="Permalink to &quot;Filtrage&quot;">​</a></h2><p>Filtrez vos entrees de temps par :</p><ul><li><strong>Client</strong> -- Voir le temps par client</li><li><strong>Projet</strong> -- Voir le temps par projet</li><li><strong>Plage de dates</strong> -- Periode specifique</li><li><strong>Statut facturable</strong> -- Facturable vs. non facturable</li><li><strong>Statut de facturation</strong> -- Facture vs. non facture</li></ul><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><ul><li><strong>Marquer comme facturable</strong> -- Definir plusieurs entrees comme facturables</li><li><strong>Creer une facture</strong> -- Facturer plusieurs entrees a la fois</li><li><strong>Archiver</strong> -- Deplacer les entrees vers les archives</li><li><strong>Supprimer</strong> -- Supprimer des entrees</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Enregistrez le temps quotidiennement pour des archives precises</li><li>Utilisez le filtre par projet pour voir les totaux de temps par projet</li><li>Verifiez regulierement le temps non facture pour eviter de manquer des heures facturables</li><li>Le profil de tableau de bord base sur les projets met en avant les indicateurs de suivi du temps</li></ul>',23)])])}const g=r(i,[["render",l]]);export{c as __pageData,g as default};
